import javax.swing.*;public class TesteComSwing {    public static void main(String[] args) {        String input = JOptionPane.showInputDialog("Fala a velocidade: ");        double v =  Double.parseDouble(input);        String tempo = JOptionPane.showInputDialog("Fala o tempo em horas: ");        double t = Double.parseDouble(tempo);        double res = v * t;        JOptionPane.showInputDialog(null, "Resultado " + res + " KM");    }}